from __future__ import annotations

import json
import math
import re
from collections import deque
from datetime import datetime
from pathlib import Path
from typing import Any

import pandas as pd

DEFAULT_PRICE_HISTORY_PATH = Path("/Users/ling/.openclaw/workspace/data/a_stock_history.csv")

BUY_SIDES = {"BUY", "B", "LONG", "买"}


def normalize_ts_code(value: Any) -> str:
    text = str(value or "").strip().upper()
    if not text or text == "NAN":
        return ""
    if text.endswith(".XSHG"):
        return f"{text[:-5]}.SH"
    if text.endswith(".XSHE"):
        return f"{text[:-5]}.SZ"
    if text.endswith((".SH", ".SZ", ".BJ", ".HK")):
        return text
    if text.isdigit() and len(text) == 6:
        if text.startswith(("600", "601", "603", "605", "688")):
            return f"{text}.SH"
        if text.startswith(("000", "001", "002", "003", "300", "301")):
            return f"{text}.SZ"
    return text


def is_a_share_stock(ts_code: str) -> bool:
    code = normalize_ts_code(ts_code)
    if "." not in code:
        return False
    symbol, market = code.split(".", 1)
    if market == "SH":
        return symbol.startswith(("600", "601", "603", "605", "688"))
    if market == "SZ":
        return symbol.startswith(("000", "001", "002", "003", "300", "301"))
    return False


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def parse_optional_float(value: Any) -> float | None:
    if value is None:
        return None
    text = str(value).replace(",", "").strip()
    if not text or text.lower() == "none":
        return None
    try:
        return float(text)
    except Exception:
        return None


def parse_int(value: Any, default: int = 0) -> int:
    try:
        return int(float(str(value).replace(",", "").strip()))
    except Exception:
        return default


def pct_change(base: float, current: float) -> float:
    """Calculate percentage change. Returns NaN for invalid inputs (zero/negative)."""
    if base <= 0 or current <= 0:
        return float('nan')
    return (current / base - 1.0) * 100.0


def clamp(value: float, lower: float, upper: float) -> float:
    return max(lower, min(upper, value))


def parse_date_tag(value: Any) -> int:
    text = str(value or "").strip()
    digits = re.sub(r"\D", "", text)
    if len(digits) >= 8:
        return parse_int(digits[:8], 0)
    return 0


def latest_report_file(report_dir: Path, patterns: list[str], cutoff_date: int = 0) -> Path | None:
    def sort_key(path: Path) -> tuple[int, float, str]:
        return (parse_date_tag(path.stem), path.stat().st_mtime, path.name)

    files: list[Path] = []
    for pattern in patterns:
        files.extend(report_dir.glob(pattern))
    if not files:
        return None
    if cutoff_date > 0:
        eligible = [path for path in files if parse_date_tag(path.stem) <= 0 or parse_date_tag(path.stem) <= cutoff_date]
        if not eligible:
            return None
        files = eligible
    return max(files, key=sort_key)


def resolve_path(value: Any, *, base_dir: Path) -> Path | None:
    text = str(value or "").strip()
    if not text:
        return None
    path = Path(text)
    if not path.is_absolute():
        path = (base_dir / path).resolve()
    return path


def first_existing_column(frame: pd.DataFrame, candidates: list[str]) -> str:
    for candidate in candidates:
        if candidate in frame.columns:
            return candidate
    return ""


def load_holdings(path: Path | None) -> pd.DataFrame:
    columns = ["ts_code", "qty", "cost_price", "name"]
    if path is None or not path.exists():
        return pd.DataFrame(columns=columns)

    frame = pd.read_csv(path)
    if frame.empty:
        return pd.DataFrame(columns=columns)

    code_col = first_existing_column(frame, ["ts_code", "symbol", "security", "code"])
    qty_col = first_existing_column(frame, ["qty", "quantity", "shares", "position", "current_qty"])
    cost_col = first_existing_column(frame, ["cost_price", "cost", "avg_cost", "hold_cost", "price_cost"])
    name_col = first_existing_column(frame, ["name", "security_name"])
    if not code_col or not qty_col:
        return pd.DataFrame(columns=columns)

    out = pd.DataFrame()
    out["ts_code"] = frame[code_col].map(normalize_ts_code)
    out["qty"] = pd.to_numeric(frame[qty_col], errors="coerce").fillna(0).astype(int)
    out["cost_price"] = (
        pd.to_numeric(frame[cost_col], errors="coerce").fillna(0.0) if cost_col else 0.0
    )
    out["name"] = frame[name_col].fillna("").astype(str) if name_col else ""
    out = out[(out["qty"] > 0) & out["ts_code"].map(is_a_share_stock)].copy()
    out = out.drop_duplicates(subset=["ts_code"], keep="first").reset_index(drop=True)
    return out[columns]


def load_latest_buy_dates(path: Path | None, codes: set[str], cutoff_date: int = 0) -> dict[str, int]:
    if path is None or not path.exists() or not codes:
        return {}

    frame = pd.read_csv(path)
    if frame.empty:
        return {}

    code_col = first_existing_column(frame, ["ts_code", "symbol", "security", "code"])
    side_col = first_existing_column(frame, ["side", "action", "direction"])
    date_col = first_existing_column(frame, ["trade_date", "date", "biz_date"])
    if not code_col or not date_col:
        return {}

    out = pd.DataFrame()
    out["ts_code"] = frame[code_col].map(normalize_ts_code)
    out["trade_date"] = frame[date_col].map(parse_date_tag)
    if side_col:
        out["side"] = frame[side_col].fillna("").astype(str).str.upper().str.strip()
        out = out[out["side"].isin(BUY_SIDES)]
    out = out[(out["trade_date"] > 0) & out["ts_code"].isin(codes)].copy()
    if cutoff_date > 0:
        out = out[out["trade_date"] <= cutoff_date].copy()
    if out.empty:
        return {}
    grouped = out.groupby("ts_code", as_index=False)["trade_date"].max()
    return dict(zip(grouped["ts_code"], grouped["trade_date"]))


def load_price_snapshot(
    price_history_path: Path,
    codes: set[str],
    entry_dates: dict[str, int],
    cutoff_date: int = 0,
) -> tuple[dict[str, float], dict[str, float], int]:
    """Load latest price snapshot using fully vectorized operations."""
    peak_high: dict[str, float] = {code: 0.0 for code in codes}
    latest_trade_date = 0
    if not price_history_path.exists() or not codes:
        return {}, peak_high, latest_trade_date

    # Single pass: filter, aggregate using vectorized groupby
    all_data = []
    for chunk in pd.read_csv(
        price_history_path,
        usecols=["ts_code", "trade_date", "high", "close"],
        chunksize=500000,
    ):
        chunk["ts_code"] = chunk["ts_code"].astype(str).str.upper().str.strip()
        chunk = chunk[chunk["ts_code"].isin(codes)].copy()
        if chunk.empty:
            continue

        chunk["trade_date"] = pd.to_numeric(chunk["trade_date"], errors="coerce").fillna(0).astype(int)
        chunk["high"] = pd.to_numeric(chunk["high"], errors="coerce").fillna(0)
        chunk["close"] = pd.to_numeric(chunk["close"], errors="coerce").fillna(0)
        chunk = chunk[(chunk["trade_date"] > 0) & (chunk["close"] > 0)]
        if cutoff_date > 0:
            chunk = chunk[chunk["trade_date"] <= cutoff_date]
        if chunk.empty:
            continue

        all_data.append(chunk)

    if not all_data:
        return {}, peak_high, latest_trade_date

    df = pd.concat(all_data, ignore_index=True)
    latest_trade_date = int(df["trade_date"].max())

    # Vectorized: latest close per code (groupby idxmax)
    idx = df.groupby("ts_code")["trade_date"].idxmax()
    close_map = df.loc[idx, ["ts_code", "close"]].set_index("ts_code")["close"].to_dict()

    # Vectorized: peak high since entry_date per code
    for code, entry_date in entry_dates.items():
        code_df = df[df["ts_code"] == code]
        if entry_date > 0:
            code_df = code_df[code_df["trade_date"] >= entry_date]
        if not code_df.empty:
            peak_high[code] = float(code_df["high"].max())

    # Clean up
    del df, all_data
    return close_map, peak_high, latest_trade_date


def load_latest_ma_snapshot(
    price_history_path: Path,
    codes: set[str],
    window: int,
    cutoff_date: int = 0,
) -> dict[str, float]:
    """Load latest MA using vectorized operations."""
    if not price_history_path.exists() or not codes or window <= 0:
        return {}

    # Collect relevant data using vectorized ops
    all_data = []
    for chunk in pd.read_csv(
        price_history_path,
        usecols=["ts_code", "trade_date", "close"],
        chunksize=500000,
    ):
        chunk["ts_code"] = chunk["ts_code"].astype(str).str.upper().str.strip()
        chunk = chunk[chunk["ts_code"].isin(codes)].copy()
        if chunk.empty:
            continue

        chunk["trade_date"] = pd.to_numeric(chunk["trade_date"], errors="coerce").fillna(0).astype(int)
        chunk["close"] = pd.to_numeric(chunk["close"], errors="coerce").fillna(0)
        chunk = chunk[(chunk["trade_date"] > 0) & (chunk["close"] > 0)]
        if cutoff_date > 0:
            chunk = chunk[chunk["trade_date"] <= cutoff_date]
        if chunk.empty:
            continue

        all_data.append(chunk[["ts_code", "trade_date", "close"]])

    if not all_data:
        return {}

    df = pd.concat(all_data, ignore_index=True)

    # Vectorized: for each code, get last `window` closes and compute MA
    ma_map = {}
    for code in codes:
        code_df = df[df["ts_code"] == code].sort_values("trade_date").tail(window)
        if len(code_df) >= window:
            ma_map[code] = float(code_df["close"].mean())

    del df, all_data
    return ma_map


def load_peak_state(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {"positions": {}}
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {"positions": {}}
    if not isinstance(payload, dict):
        return {"positions": {}}
    positions = payload.get("positions")
    if not isinstance(positions, dict):
        payload["positions"] = {}
    return payload


def save_peak_state(path: Path, state: dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")


def resolve_exit_config(live_config: dict[str, Any], *, project_root: Path) -> dict[str, Any]:
    if not isinstance(live_config, dict):
        live_config = {}
    defaults: dict[str, Any] = {
        "enabled": True,
        "stop_loss_pct": -5.0,
        "stop_loss_soft_pct": None,
        "stop_loss_soft_sell_ratio": 0.5,
        "stop_loss_hard_pct": None,
        "trailing_take_profit_arm_pct": 8.0,
        "trailing_take_profit_drawdown_pct": 4.0,
        "trailing_take_profit_confirm_bars": 1,
        "trailing_take_profit_below_ma_window": 0,
        "mode_cautious_target_exposure": 0.65,
        "mode_halt_target_exposure": 0.30,
        "peak_price_state_path": "research/reports/live_exit_peak_state_v1.json",
        "price_history_path": str(DEFAULT_PRICE_HISTORY_PATH),
    }
    block = live_config.get("exit_rules", {}) or {}
    if isinstance(block, dict):
        defaults.update({k: v for k, v in block.items() if v not in (None, "")})
    defaults["enabled"] = bool(defaults.get("enabled", True))
    defaults["stop_loss_pct"] = parse_float(defaults.get("stop_loss_pct"), -5.0)
    defaults["stop_loss_soft_pct"] = parse_optional_float(defaults.get("stop_loss_soft_pct"))
    defaults["stop_loss_soft_sell_ratio"] = max(0.0, min(1.0, parse_float(defaults.get("stop_loss_soft_sell_ratio"), 0.5)))
    defaults["stop_loss_hard_pct"] = parse_optional_float(defaults.get("stop_loss_hard_pct"))
    for key in [
        "trailing_take_profit_arm_pct",
        "trailing_take_profit_drawdown_pct",
        "mode_cautious_target_exposure",
        "mode_halt_target_exposure",
    ]:
        defaults[key] = parse_float(defaults.get(key), parse_float(defaults.get(key), 0.0))
    defaults["trailing_take_profit_confirm_bars"] = max(
        1,
        parse_int(defaults.get("trailing_take_profit_confirm_bars"), 1),
    )
    defaults["trailing_take_profit_below_ma_window"] = max(
        0,
        parse_int(defaults.get("trailing_take_profit_below_ma_window"), 0),
    )
    defaults["peak_price_state_path"] = str(
        resolve_path(defaults.get("peak_price_state_path"), base_dir=project_root) or ""
    )
    defaults["price_history_path"] = str(
        resolve_path(defaults.get("price_history_path"), base_dir=project_root) or DEFAULT_PRICE_HISTORY_PATH
    )
    return defaults


def resolve_stop_loss_rules(cfg: dict[str, Any]) -> dict[str, Any]:
    legacy_pct = parse_optional_float(cfg.get("stop_loss_pct"))
    soft_pct = parse_optional_float(cfg.get("stop_loss_soft_pct"))
    hard_pct = parse_optional_float(cfg.get("stop_loss_hard_pct"))
    soft_sell_ratio = max(0.0, min(1.0, parse_float(cfg.get("stop_loss_soft_sell_ratio"), 0.5)))

    if soft_pct is None and hard_pct is None:
        return {
            "mode": "single",
            "single_pct": legacy_pct if legacy_pct is not None else -5.0,
            "soft_pct": None,
            "hard_pct": None,
            "soft_sell_ratio": 1.0,
        }

    if soft_pct is None and hard_pct is not None:
        return {
            "mode": "single",
            "single_pct": hard_pct,
            "soft_pct": None,
            "hard_pct": None,
            "soft_sell_ratio": 1.0,
        }

    if soft_pct is not None and hard_pct is None:
        hard_pct = legacy_pct if legacy_pct is not None else soft_pct

    ordered = sorted([x for x in [soft_pct, hard_pct] if x is not None], reverse=True)
    if len(ordered) < 2:
        return {
            "mode": "single",
            "single_pct": ordered[0] if ordered else (legacy_pct if legacy_pct is not None else -5.0),
            "soft_pct": None,
            "hard_pct": None,
            "soft_sell_ratio": 1.0,
        }

    resolved_soft_pct = ordered[0]
    resolved_hard_pct = ordered[1]
    if soft_sell_ratio <= 0.0:
        return {
            "mode": "single",
            "single_pct": resolved_hard_pct,
            "soft_pct": None,
            "hard_pct": None,
            "soft_sell_ratio": 1.0,
        }
    if soft_sell_ratio >= 1.0 or resolved_soft_pct <= resolved_hard_pct:
        return {
            "mode": "single",
            "single_pct": resolved_soft_pct,
            "soft_pct": None,
            "hard_pct": None,
            "soft_sell_ratio": 1.0,
        }

    return {
        "mode": "dual",
        "single_pct": None,
        "soft_pct": resolved_soft_pct,
        "hard_pct": resolved_hard_pct,
        "soft_sell_ratio": soft_sell_ratio,
    }


def compute_partial_exit_qty(qty: int, sell_ratio: float) -> int:
    if qty <= 0 or sell_ratio <= 0:
        return 0
    return min(qty, max(1, int(math.ceil(qty * sell_ratio))))


def resolve_soft_stop_reissue_qty(prev_state: dict[str, Any], current_qty: int, default_reduce_qty: int) -> int:
    trigger_qty = parse_int(prev_state.get("soft_trigger_qty"), 0)
    remaining_qty = parse_int(prev_state.get("soft_expected_remaining_qty"), -1)
    reduce_qty = parse_int(prev_state.get("soft_reduce_qty"), 0)

    if trigger_qty > 0 and current_qty > trigger_qty:
        return default_reduce_qty

    if remaining_qty < 0:
        return 0
    if current_qty <= remaining_qty:
        return 0

    pending_reduce_qty = current_qty - remaining_qty
    if reduce_qty > 0:
        pending_reduce_qty = min(pending_reduce_qty, reduce_qty)
    return max(0, pending_reduce_qty)


def build_exit_signal_row(
    *,
    trade_date: str,
    ts_code: str,
    qty: int,
    ref_price: float,
    reason: str,
    exit_type: str,
    score: float,
    reduce_score: float | None = None,
    reduce_rank_reason: str = "",
) -> dict[str, Any]:
    now_text = datetime.now().astimezone().isoformat()
    return {
        "trade_date": trade_date,
        "ts_code": ts_code,
        "signal_type": "SELL",
        "score": round(score, 6),
        "target_weight": 0.0,
        "target_qty": int(max(0, qty)),
        "ref_price": round(ref_price, 4) if ref_price > 0 else None,
        "strategy_id": "exit_engine_v1",
        "risk_flag": "exit_engine",
        "comment": reason,
        "source_run_id": f"exit_engine_v1_{trade_date.replace('-', '')}",
        "generated_at": now_text,
        "approved": True,
        "risk_status": "exit",
        "risk_adjustment": exit_type,
        "exit_type": exit_type,
        "exit_reason": reason,
        "reason": reason,
        "reduce_score": round(parse_float(reduce_score, 0.0), 6) if reduce_score is not None else None,
        "reduce_rank_reason": reduce_rank_reason,
    }


def compute_mode_de_risk_reduce_score(
    *,
    in_candidates: bool,
    return_pct: float,
    buy_score: float,
) -> tuple[float, str]:
    non_candidate_bonus = 10.0 if not in_candidates else 0.0
    return_component = clamp(-parse_float(return_pct, 0.0) / 5.0, -2.0, 2.0)
    weak_buy_component = 0.5 * (1.0 - clamp(parse_float(buy_score, 0.0), 0.0, 1.0))
    total = non_candidate_bonus + return_component + weak_buy_component
    detail = (
        f"non_candidate_bonus={non_candidate_bonus:.2f};"
        f"return_component={return_component:.2f};"
        f"weak_buy_component={weak_buy_component:.2f}"
    )
    return round(total, 6), detail


def generate_exit_signals(
    *,
    trade_date: str,
    account_nav: float,
    mode: str,
    live_config: dict[str, Any],
    project_root: Path,
    report_dir: Path,
    holdings_path: Path | None,
    trade_history_path: Path | None = None,
    lot_size: int = 100,
    candidate_codes: set[str] | None = None,
    buy_score_map: dict[str, float] | None = None,
) -> tuple[pd.DataFrame, dict[str, Any]]:
    cfg = resolve_exit_config(live_config, project_root=project_root)
    summary: dict[str, Any] = {
        "enabled": bool(cfg.get("enabled", True)),
        "holdings_path": "",
        "trade_history_path": "",
        "holdings_count": 0,
        "price_hit_count": 0,
        "stop_loss_count": 0,
        "stop_loss_reduce_count": 0,
        "stop_loss_hard_count": 0,
        "trailing_stop_count": 0,
        "de_risk_count": 0,
        "mode": mode,
        "target_exposure": None,
        "current_exposure": None,
        "post_exit_exposure": None,
        "state_path": str(cfg.get("peak_price_state_path", "")),
        "de_risk_score_rule": (
            "reduce_score=10*(非候选股) + clip(-return_pct/5,-2,2) + 0.5*(1-clamp(buy_score,0,1))"
        ),
    }
    empty = pd.DataFrame()
    if not bool(cfg.get("enabled", True)):
        summary["reason"] = "disabled"
        return empty, summary
    cutoff_date = parse_date_tag(trade_date)

    holdings_file = holdings_path
    if holdings_file is None:
        holdings_file = latest_report_file(
            report_dir,
            ["broker_api_holdings_*.csv", "ths_app_holdings_*.csv", "account_holdings_*.csv"],
            cutoff_date=cutoff_date,
        )
    if holdings_file is None or not holdings_file.exists():
        summary["reason"] = "holdings_not_found"
        return empty, summary
    summary["holdings_path"] = str(holdings_file)

    holdings = load_holdings(holdings_file)
    summary["holdings_count"] = int(len(holdings))
    if holdings.empty:
        summary["reason"] = "holdings_empty"
        return empty, summary

    if trade_history_path is None:
        trade_history_path = latest_report_file(
            report_dir,
            ["ths_app_trades_*.csv", "ths_trades_*.csv"],
            cutoff_date=cutoff_date,
        )
    if trade_history_path is not None and trade_history_path.exists():
        summary["trade_history_path"] = str(trade_history_path)

    codes = set(holdings["ts_code"].tolist())
    entry_dates = load_latest_buy_dates(trade_history_path, codes, cutoff_date=cutoff_date)

    state_path = Path(str(cfg["peak_price_state_path"]))
    state = load_peak_state(state_path)
    old_positions = state.get("positions", {}) or {}
    for code, payload in old_positions.items():
        if code not in entry_dates and isinstance(payload, dict):
            entry_date = parse_date_tag(payload.get("entry_date"))
            if entry_date > 0:
                entry_dates[code] = entry_date

    close_map, peak_map, latest_trade_date = load_price_snapshot(
        Path(str(cfg["price_history_path"])),
        codes,
        entry_dates,
        cutoff_date=cutoff_date,
    )
    summary["price_hit_count"] = int(sum(1 for code in codes if parse_float(close_map.get(code), 0.0) > 0))

    candidate_codes = {normalize_ts_code(code) for code in (candidate_codes or set()) if normalize_ts_code(code)}
    buy_score_map = {normalize_ts_code(k): parse_float(v, 0.0) for k, v in (buy_score_map or {}).items()}
    stop_loss_rules = resolve_stop_loss_rules(cfg)
    summary["stop_loss_mode"] = str(stop_loss_rules.get("mode", "single"))
    if stop_loss_rules.get("mode") == "dual":
        summary["stop_loss_soft_pct"] = stop_loss_rules.get("soft_pct")
        summary["stop_loss_hard_pct"] = stop_loss_rules.get("hard_pct")
        summary["stop_loss_soft_sell_ratio"] = stop_loss_rules.get("soft_sell_ratio")
    else:
        summary["stop_loss_pct"] = stop_loss_rules.get("single_pct")
    arm_pct = parse_float(cfg.get("trailing_take_profit_arm_pct"), 8.0)
    trailing_dd_pct = abs(parse_float(cfg.get("trailing_take_profit_drawdown_pct"), 4.0))
    trailing_confirm_bars = max(1, parse_int(cfg.get("trailing_take_profit_confirm_bars"), 1))
    trailing_below_ma_window = max(0, parse_int(cfg.get("trailing_take_profit_below_ma_window"), 0))
    summary["trailing_take_profit_arm_pct"] = arm_pct
    summary["trailing_take_profit_drawdown_pct"] = trailing_dd_pct
    summary["trailing_take_profit_confirm_bars"] = trailing_confirm_bars
    summary["trailing_take_profit_below_ma_window"] = trailing_below_ma_window
    trailing_ma_map = load_latest_ma_snapshot(
        Path(str(cfg["price_history_path"])),
        codes,
        trailing_below_ma_window,
        cutoff_date=cutoff_date,
    ) if trailing_below_ma_window > 0 else {}
    exposure_target_map = {
        "normal": 1.0,
        "cautious": max(0.0, min(1.0, parse_float(cfg.get("mode_cautious_target_exposure"), 0.65))),
        "halt": max(0.0, min(1.0, parse_float(cfg.get("mode_halt_target_exposure"), 0.30))),
    }

    planned_rows: list[dict[str, Any]] = []
    current_positions: dict[str, dict[str, Any]] = {}
    holdings_records: list[dict[str, Any]] = []
    for row in holdings.to_dict(orient="records"):
        code = str(row["ts_code"])
        qty = parse_int(row.get("qty"), 0)
        cost_price = parse_float(row.get("cost_price"), 0.0)
        ref_price = parse_float(close_map.get(code), 0.0)
        prev_state = old_positions.get(code, {}) if isinstance(old_positions.get(code), dict) else {}
        hist_peak = parse_float(peak_map.get(code), 0.0)
        peak_price = max(
            ref_price,
            hist_peak,
            parse_float(prev_state.get("peak_price"), 0.0),
        )
        entry_date = entry_dates.get(code, 0)
        if entry_date <= 0:
            entry_date = parse_date_tag(prev_state.get("entry_date"))
        return_pct = pct_change(cost_price, ref_price)
        peak_return_pct = pct_change(cost_price, peak_price)
        drawdown_from_peak_pct = pct_change(peak_price, ref_price)
        armed = bool(prev_state.get("armed", False)) or peak_return_pct >= arm_pct
        arm_date = prev_state.get("arm_date", "")
        if armed and not arm_date:
            arm_date = trade_date
        trailing_triggered = armed and peak_return_pct >= arm_pct and drawdown_from_peak_pct <= -trailing_dd_pct
        prev_trailing_bars = max(0, parse_int(prev_state.get("trailing_trigger_bars"), 0))
        prev_trailing_last_date = str(prev_state.get("trailing_trigger_last_date", "") or "")
        prev_trailing_start_date = str(prev_state.get("trailing_trigger_start_date", "") or "")
        if trailing_triggered:
            if prev_trailing_bars > 0 and prev_trailing_last_date == trade_date:
                trailing_trigger_bars = prev_trailing_bars
                trailing_trigger_start_date = prev_trailing_start_date or trade_date
            elif prev_trailing_bars > 0:
                trailing_trigger_bars = prev_trailing_bars + 1
                trailing_trigger_start_date = prev_trailing_start_date or trade_date
            else:
                trailing_trigger_bars = 1
                trailing_trigger_start_date = trade_date
            trailing_trigger_last_date = trade_date
        else:
            trailing_trigger_bars = 0
            trailing_trigger_start_date = ""
            trailing_trigger_last_date = ""
        trailing_ma_value = parse_float(trailing_ma_map.get(code), 0.0)
        stop_loss_stage = str(prev_state.get("stop_loss_stage", "") or "").strip().lower()
        if stop_loss_stage not in {"soft", "hard"}:
            stop_loss_stage = ""
        if stop_loss_stage == "soft":
            soft_trigger_qty = parse_int(prev_state.get("soft_trigger_qty"), 0)
            if soft_trigger_qty > 0 and qty > soft_trigger_qty:
                stop_loss_stage = ""

        current_positions[code] = {
            "peak_price": round(peak_price, 6),
            "peak_date": str(latest_trade_date or parse_date_tag(trade_date) or ""),
            "entry_date": str(entry_date or ""),
            "armed": armed,
            "arm_date": arm_date,
            "stop_loss_stage": stop_loss_stage,
            "trailing_trigger_bars": trailing_trigger_bars,
            "trailing_trigger_start_date": trailing_trigger_start_date,
            "trailing_trigger_last_date": trailing_trigger_last_date,
            "trailing_ma_value": round(trailing_ma_value, 6) if trailing_ma_value > 0 else None,
            "last_ref_price": round(ref_price, 6),
            "updated_at": datetime.now().astimezone().isoformat(),
        }

        market_value = round(qty * ref_price, 2) if qty > 0 and ref_price > 0 else 0.0
        record = {
            "ts_code": code,
            "qty": qty,
            "cost_price": cost_price,
            "ref_price": ref_price,
            "return_pct": return_pct,
            "peak_price": peak_price,
            "peak_return_pct": peak_return_pct,
            "drawdown_from_peak_pct": drawdown_from_peak_pct,
            "market_value": market_value,
            "in_candidates": code in candidate_codes,
            "buy_score": parse_float(buy_score_map.get(code), 0.0),
        }
        reduce_score, reduce_rank_reason = compute_mode_de_risk_reduce_score(
            in_candidates=bool(record["in_candidates"]),
            return_pct=parse_float(record["return_pct"], 0.0),
            buy_score=parse_float(record["buy_score"], 0.0),
        )
        record["reduce_score"] = reduce_score
        record["reduce_rank_reason"] = reduce_rank_reason
        holdings_records.append(record)

        if qty <= 0 or ref_price <= 0 or cost_price <= 0:
            continue
        if stop_loss_rules.get("mode") == "dual":
            hard_stop_loss_pct = parse_float(stop_loss_rules.get("hard_pct"), -8.0)
            soft_stop_loss_pct = parse_float(stop_loss_rules.get("soft_pct"), -5.0)
            soft_sell_ratio = parse_float(stop_loss_rules.get("soft_sell_ratio"), 0.5)
            if return_pct <= hard_stop_loss_pct:
                current_positions[code]["stop_loss_stage"] = "hard"
                planned_rows.append(
                    build_exit_signal_row(
                        trade_date=trade_date,
                        ts_code=code,
                        qty=qty,
                        ref_price=ref_price,
                        reason=f"exit_engine:stop_loss_hard 持仓收益={return_pct:.2f}% <= {hard_stop_loss_pct:.2f}%",
                        exit_type="stop_loss_hard",
                        score=1.0,
                    )
                )
                summary["stop_loss_count"] += 1
                summary["stop_loss_hard_count"] += 1
                continue
            if return_pct <= soft_stop_loss_pct:
                reduce_qty = compute_partial_exit_qty(qty, soft_sell_ratio)
                if stop_loss_stage == "soft":
                    reduce_qty = resolve_soft_stop_reissue_qty(prev_state, qty, reduce_qty)
                if reduce_qty >= qty:
                    current_positions[code]["stop_loss_stage"] = "hard"
                    planned_rows.append(
                        build_exit_signal_row(
                            trade_date=trade_date,
                            ts_code=code,
                            qty=qty,
                            ref_price=ref_price,
                            reason=f"exit_engine:stop_loss_hard 持仓收益={return_pct:.2f}% <= {soft_stop_loss_pct:.2f}% (软止损比例触发全卖)",
                            exit_type="stop_loss_hard",
                            score=1.0,
                        )
                    )
                    summary["stop_loss_count"] += 1
                    summary["stop_loss_hard_count"] += 1
                elif reduce_qty > 0:
                    current_positions[code]["stop_loss_stage"] = "soft"
                    current_positions[code]["stop_loss_soft_trade_date"] = trade_date
                    current_positions[code]["soft_trigger_qty"] = qty
                    current_positions[code]["soft_reduce_qty"] = reduce_qty
                    current_positions[code]["soft_expected_remaining_qty"] = max(0, qty - reduce_qty)
                    planned_rows.append(
                        build_exit_signal_row(
                            trade_date=trade_date,
                            ts_code=code,
                            qty=reduce_qty,
                            ref_price=ref_price,
                            reason=(
                                f"exit_engine:stop_loss_reduce 持仓收益={return_pct:.2f}% <= {soft_stop_loss_pct:.2f}% "
                                f"减仓比例={soft_sell_ratio * 100:.0f}%"
                            ),
                            exit_type="stop_loss_reduce",
                            score=0.98,
                        )
                    )
                    summary["stop_loss_count"] += 1
                    summary["stop_loss_reduce_count"] += 1
                continue
        else:
            stop_loss_pct = parse_float(stop_loss_rules.get("single_pct"), -5.0)
            if return_pct <= stop_loss_pct:
                current_positions[code]["stop_loss_stage"] = "hard"
                planned_rows.append(
                    build_exit_signal_row(
                        trade_date=trade_date,
                        ts_code=code,
                        qty=qty,
                        ref_price=ref_price,
                        reason=f"exit_engine:stop_loss 持仓收益={return_pct:.2f}% <= {stop_loss_pct:.2f}%",
                        exit_type="stop_loss",
                        score=1.0,
                    )
                )
                summary["stop_loss_count"] += 1
                summary["stop_loss_hard_count"] += 1
                continue
        trailing_time_confirmed = trailing_trigger_bars >= trailing_confirm_bars
        trailing_ma_confirmed = (
            trailing_below_ma_window <= 0
            or trailing_ma_value <= 0
            or ref_price <= trailing_ma_value
        )
        if trailing_triggered and trailing_time_confirmed and trailing_ma_confirmed:
            planned_rows.append(
                build_exit_signal_row(
                    trade_date=trade_date,
                    ts_code=code,
                    qty=qty,
                    ref_price=ref_price,
                    reason=(
                        "exit_engine:trailing_take_profit "
                        f"峰值收益={peak_return_pct:.2f}% 当前收益={return_pct:.2f}% "
                        f"峰值回撤={drawdown_from_peak_pct:.2f}% "
                        f"confirm_bars={trailing_trigger_bars}/{trailing_confirm_bars}"
                        + (
                            f" ma{trailing_below_ma_window}={trailing_ma_value:.2f}"
                            if trailing_below_ma_window > 0 and trailing_ma_value > 0
                            else ""
                        )
                    ),
                    exit_type="trailing_take_profit",
                    score=0.95,
                )
            )
            summary["trailing_stop_count"] += 1

    state["positions"] = current_positions
    save_peak_state(state_path, state)

    total_market_value = sum(parse_float(row["market_value"], 0.0) for row in holdings_records)
    summary["current_exposure"] = round(total_market_value / account_nav, 4) if account_nav > 0 else None

    planned_sell_codes = {str(row["ts_code"]) for row in planned_rows}
    planned_sell_value = sum(
        parse_float(row.get("ref_price"), 0.0) * parse_int(row.get("target_qty"), 0)
        for row in planned_rows
    )
    target_exposure = exposure_target_map.get(mode, 1.0)
    summary["target_exposure"] = round(target_exposure, 4)
    residual_market_value = max(0.0, total_market_value - planned_sell_value)
    summary["post_exit_exposure"] = round(residual_market_value / account_nav, 4) if account_nav > 0 else None

    if mode in {"cautious", "halt"} and account_nav > 0:
        target_market_value = account_nav * target_exposure
        excess_market_value = residual_market_value - target_market_value
        if excess_market_value > 0:
            ranked_holdings = sorted(
                [row for row in holdings_records if row["ts_code"] not in planned_sell_codes],
                key=lambda row: (
                    -parse_float(row.get("reduce_score"), 0.0),
                    row["ts_code"],
                ),
            )
            summary["de_risk_ranked_preview"] = [
                {
                    "ts_code": str(row["ts_code"]),
                    "reduce_score": round(parse_float(row.get("reduce_score"), 0.0), 6),
                    "reduce_rank_reason": str(row.get("reduce_rank_reason") or ""),
                }
                for row in ranked_holdings[:5]
            ]
            for row in ranked_holdings:
                if excess_market_value <= 0:
                    break
                qty = parse_int(row["qty"], 0)
                ref_price = parse_float(row["ref_price"], 0.0)
                if qty <= 0 or ref_price <= 0:
                    continue
                if lot_size > 0 and qty > lot_size:
                    needed_lots = math.ceil(excess_market_value / ref_price / lot_size)
                    sell_qty = min(qty, max(lot_size, needed_lots * lot_size))
                else:
                    sell_qty = qty
                if sell_qty <= 0:
                    continue
                sell_value = min(parse_float(row["market_value"], 0.0), sell_qty * ref_price)
                excess_market_value -= sell_value
                planned_rows.append(
                    build_exit_signal_row(
                        trade_date=trade_date,
                        ts_code=str(row["ts_code"]),
                        qty=sell_qty,
                        ref_price=ref_price,
                        reason=(
                            f"exit_engine:mode_de_risk mode={mode} "
                            f"目标仓位={target_exposure:.2f} 当前持仓收益={row['return_pct']:.2f}% "
                            f"reduce_score={parse_float(row.get('reduce_score'), 0.0):.3f}"
                        ),
                        exit_type="mode_de_risk",
                        score=0.8,
                        reduce_score=parse_float(row.get("reduce_score"), 0.0),
                        reduce_rank_reason=str(row.get("reduce_rank_reason") or ""),
                    )
                )
                summary["de_risk_count"] += 1
            reduced_market_value = max(
                0.0,
                total_market_value
                - sum(
                    parse_float(row.get("ref_price"), 0.0) * parse_int(row.get("target_qty"), 0)
                    for row in planned_rows
                ),
            )
            summary["post_exit_exposure"] = round(reduced_market_value / account_nav, 4) if account_nav > 0 else None

    if not planned_rows:
        summary["reason"] = "no_exit_trigger"
        return empty, summary

    planned = pd.DataFrame(planned_rows)
    planned = planned.sort_values(["ts_code", "score"], ascending=[True, False])
    planned = planned.drop_duplicates(subset=["trade_date", "ts_code", "signal_type"], keep="first").reset_index(drop=True)
    summary["exit_rows"] = int(len(planned))
    return planned, summary

"""
订单执行模拟器 - 模拟涨跌停/流动性约束下的订单成交情况

职责：
1. 涨停日：买入订单无法成交
2. 跌停日：卖出订单无法成交
3. 部分成交：大单按成交率分批执行
4. T+1 限制：当日买入无法当日卖出
"""

from __future__ import annotations

import math
from dataclasses import dataclass, field
from typing import Optional


@dataclass
class ExecutionResult:
    """订单执行结果"""
    ts_code: str
    side: str  # BUY / SELL
    requested_qty: int
    filled_qty: int          # 实际成交数量
    fill_price: float         # 成交价（若无成交则为0）
    rejected: bool = False
    rejection_reason: str = ""
    slippage_bps: float = 0.0  # 滑点（基点）

    @property
    def fill_rate(self) -> float:
        """成交率"""
        if self.requested_qty <= 0:
            return 0.0
        return self.filled_qty / self.requested_qty


@dataclass
class DailyMarketData:
    """单日市场数据"""
    ts_code: str
    trade_date: int
    open: float
    high: float
    low: float
    close: float
    limit_up: float
    limit_down: float
    suspended: bool = False
    adv20: float = 0.0  # 20日平均成交量


@dataclass
class Position:
    """持仓记录（用于T+1追踪）"""
    ts_code: str
    buy_date: int       # 买入日期 (YYYYMMDD)
    qty: int
    avg_price: float


@dataclass
class ExecutionConfig:
    """执行模拟配置"""
    # 涨跌停约束
    enforce_limit_up_block: bool = True    # 涨停日禁止买入
    enforce_limit_down_block: bool = True   # 跌停日禁止卖出

    # 流动性约束
    max_order_to_adv_ratio: float = 0.02   # 单笔订单不超过ADV20的2%
    enforce_liquidity: bool = False         # 是否强制执行流动性约束

    # 部分成交
    enable_partial_fill: bool = True        # 启用部分成交模拟
    partial_fill_rate: float = 0.8          # 大单部分成交率（实际可成交量/申请量）

    # 滑点（基点）
    buy_slippage_bps: float = 8.0          # 买入滑点 8bps
    sell_slippage_bps: float = 5.0         # 卖出滑点 5bps
    limit_up_slippage_bps: float = 5.0     # 涨停买入额外滑点

    # 成交延迟（天）
    execution_delay_days: int = 1            # 信号到成交的延迟（T+1）


class ExecutionSimulator:
    """
    订单执行模拟器

    核心规则：
    1. 涨停日买入 → 拒绝（无法买入）
    2. 跌停日卖出 → 拒绝（无法卖出）
    3. 超出流动性 → 部分成交
    4. T+1限制 → 当日买入次日才能卖
    """

    def __init__(self, config: Optional[ExecutionConfig] = None):
        self.config = config or ExecutionConfig()
        # 持仓记录: ts_code -> Position
        self._positions: dict[str, Position] = {}
        # 成交记录: trade_date -> list[ExecutionResult]
        self._fill_history: dict[int, list[ExecutionResult]] = {}

    def execute_buy(
        self,
        ts_code: str,
        requested_qty: int,
        price: float,
        market_data: DailyMarketData,
        trade_date: int,
    ) -> ExecutionResult:
        """
        执行买入订单

        Args:
            ts_code: 股票代码
            requested_qty: 申请买入数量
            price: 限价（通常为涨停价）
            market_data: 当日市场数据
            trade_date: 交易日期

        Returns:
            ExecutionResult: 执行结果
        """
        if requested_qty <= 0:
            return ExecutionResult(
                ts_code=ts_code, side="BUY",
                requested_qty=0, filled_qty=0, fill_price=0,
                rejected=True, rejection_reason="requested_qty <= 0"
            )

        # 规则1: 停牌
        if market_data.suspended:
            return self._reject(
                ts_code, "BUY", requested_qty, 0,
                f"停牌日无法买入"
            )

        # 规则2: 涨停日禁止买入
        if self.config.enforce_limit_up_block:
            if market_data.close >= market_data.limit_up - 1e-8:
                return self._reject(
                    ts_code, "BUY", requested_qty, 0,
                    f"涨停日无法买入 (close={market_data.close:.2f}, limit_up={market_data.limit_up:.2f})"
                )

        # 规则3: 流动性约束
        fill_qty = requested_qty
        fill_price = price
        slippage = self.config.buy_slippage_bps

        if self.config.enforce_liquidity and market_data.adv20 > 0:
            max_qty_by_liquidity = int(market_data.adv20 * self.config.max_order_to_adv_ratio)
            if fill_qty > max_qty_by_liquidity:
                if self.config.enable_partial_fill:
                    # 按比例成交
                    fill_ratio = min(self.config.partial_fill_rate, max_qty_by_liquidity / fill_qty)
                    fill_qty = int(fill_qty * fill_ratio)
                    slippage += 5  # 流动性不足额外滑点
                else:
                    return self._reject(
                        ts_code, "BUY", requested_qty, 0,
                        f"超出流动性限制 (qty={requested_qty}, max={max_qty_by_liquidity})"
                    )

        if fill_qty <= 0:
            return self._reject(
                ts_code, "BUY", requested_qty, 0,
                "流动性不足导致无法成交"
            )

        # 计算滑点
        fill_price = price * (1 + slippage / 10000)

        # 更新持仓（T+1生效）
        entry_date = trade_date + self.config.execution_delay_days
        self._update_position(ts_code, entry_date, fill_qty, fill_price)

        # 记录成交
        result = ExecutionResult(
            ts_code=ts_code, side="BUY",
            requested_qty=requested_qty,
            filled_qty=fill_qty,
            fill_price=fill_price,
            slippage_bps=slippage
        )
        self._record_fill(trade_date, result)

        return result

    def execute_sell(
        self,
        ts_code: str,
        requested_qty: int,
        price: float,
        market_data: DailyMarketData,
        trade_date: int,
    ) -> ExecutionResult:
        """
        执行卖出订单

        Args:
            ts_code: 股票代码
            requested_qty: 申请卖出数量
            price: 限价（通常为跌停价）
            market_data: 当日市场数据
            trade_date: 交易日期

        Returns:
            ExecutionResult: 执行结果
        """
        if requested_qty <= 0:
            return ExecutionResult(
                ts_code=ts_code, side="SELL",
                requested_qty=0, filled_qty=0, fill_price=0,
                rejected=True, rejection_reason="requested_qty <= 0"
            )

        # 规则1: 停牌
        if market_data.suspended:
            return self._reject(
                ts_code, "SELL", requested_qty, 0,
                f"停牌日无法卖出"
            )

        # 规则2: 跌停日禁止卖出
        if self.config.enforce_limit_down_block:
            if market_data.close <= market_data.limit_down + 1e-8:
                return self._reject(
                    ts_code, "SELL", requested_qty, 0,
                    f"跌停日无法卖出 (close={market_data.close:.2f}, limit_down={market_data.limit_down:.2f})"
                )

        # 规则3: T+1 限制
        position = self._positions.get(ts_code)
        if position is None or position.qty <= 0:
            return self._reject(
                ts_code, "SELL", requested_qty, 0,
                f"T+1限制：无持仓记录"
            )

        # 检查是否在T+1锁定期
        if trade_date < position.buy_date:
            return self._reject(
                ts_code, "SELL", requested_qty, 0,
                f"T+1限制：{position.buy_date}日买入，需等到{position.buy_date + 1}日才能卖出"
            )

        # 规则4: 流动性约束
        fill_qty = min(requested_qty, position.qty)
        fill_price = price
        slippage = self.config.sell_slippage_bps

        if self.config.enforce_liquidity and market_data.adv20 > 0:
            max_qty_by_liquidity = int(market_data.adv20 * self.config.max_order_to_adv_ratio)
            if fill_qty > max_qty_by_liquidity:
                if self.config.enable_partial_fill:
                    fill_ratio = min(self.config.partial_fill_rate, max_qty_by_liquidity / fill_qty)
                    fill_qty = max(1, int(fill_qty * fill_ratio))
                    slippage += 5
                else:
                    return self._reject(
                        ts_code, "SELL", requested_qty, 0,
                        f"超出流动性限制 (qty={requested_qty}, max={max_qty_by_liquidity})"
                    )

        if fill_qty <= 0:
            return self._reject(
                ts_code, "SELL", requested_qty, 0,
                "流动性不足导致无法成交"
            )

        # 计算滑点（卖出用bid）
        fill_price = price * (1 - slippage / 10000)

        # 更新持仓
        position.qty -= fill_qty
        if position.qty <= 0:
            del self._positions[ts_code]

        # 记录成交
        result = ExecutionResult(
            ts_code=ts_code, side="SELL",
            requested_qty=requested_qty,
            filled_qty=fill_qty,
            fill_price=fill_price,
            slippage_bps=slippage
        )
        self._record_fill(trade_date, result)

        return result

    def can_buy(self, market_data: DailyMarketData) -> tuple[bool, str]:
        """检查当日是否可以买入"""
        if market_data.suspended:
            return False, "停牌"
        if self.config.enforce_limit_up_block:
            if market_data.close >= market_data.limit_up - 1e-8:
                return False, "涨停"
        return True, ""

    def can_sell(self, market_data: DailyMarketData) -> tuple[bool, str]:
        """检查当日是否可以卖出"""
        if market_data.suspended:
            return False, "停牌"
        if self.config.enforce_limit_down_block:
            if market_data.close <= market_data.limit_down + 1e-8:
                return False, "跌停"
        return True, ""

    def get_position(self, ts_code: str) -> Optional[Position]:
        """获取持仓（仅返回非空持仓）"""
        pos = self._positions.get(ts_code)
        if pos and pos.qty > 0:
            return pos
        return None

    def get_positions(self) -> dict[str, Position]:
        """获取所有持仓"""
        return {k: v for k, v in self._positions.items() if v.qty > 0}

    def get_fill_history(self, trade_date: int) -> list[ExecutionResult]:
        """获取指定日期的成交记录"""
        return self._fill_history.get(trade_date, [])

    def _reject(self, ts_code: str, side: str, qty: int, price: float, reason: str) -> ExecutionResult:
        return ExecutionResult(
            ts_code=ts_code, side=side,
            requested_qty=qty, filled_qty=0, fill_price=price,
            rejected=True, rejection_reason=reason
        )

    def _update_position(self, ts_code: str, buy_date: int, qty: int, avg_price: float):
        if ts_code in self._positions:
            pos = self._positions[ts_code]
            total_cost = pos.qty * pos.avg_price + qty * avg_price
            pos.qty += qty
            pos.avg_price = total_cost / pos.qty
            # T+1: 如果补仓，保持最早的买入日期
            if buy_date < pos.buy_date:
                pos.buy_date = buy_date
        else:
            self._positions[ts_code] = Position(
                ts_code=ts_code, buy_date=buy_date, qty=qty, avg_price=avg_price
            )

    def _record_fill(self, trade_date: int, result: ExecutionResult):
        if trade_date not in self._fill_history:
            self._fill_history[trade_date] = []
        self._fill_history[trade_date].append(result)

    def reset(self):
        """重置模拟器状态（用于新回测周期）"""
        self._positions.clear()
        self._fill_history.clear()
